INSERT OR REPLACE INTO `audit_reports` (`id`, `ticker`, `year`, `report_type`, `auditor_name`, `audit_opinion`, `going_concern_issue`, `going_concern_detail`) VALUES
('VNL_2021_consolidated', 'VNL', 2021, 'consolidated', 'Công ty TNHH Kiểm toán & Tư vấn RSM Việt Nam', 'unqualified', 0, NULL),
('VNL_2015_consolidated', 'VNL', 2015, 'consolidated', 'Công ty TNHH Kiểm toán DTL', 'unqualified', 0, NULL),
('VNI_2025_consolidated', 'VNI', 2025, 'consolidated', 'AASCS', 'qualified', 1, 'Nợ ngắn hạn vượt quá tài sản ngắn hạn 109.026.345.172 VND, khả năng thanh toán bị hạn chế.'),
('VNI_2023_consolidated', 'VNI', 2023, 'consolidated', 'Công ty TNHH Dịch vụ tư vấn Tài chính – Kế toán và Kiểm toán Phía Nam (AASCS)', 'unqualified', 0, NULL),
('VNH_2025_consolidated', 'VNH', 2025, 'consolidated', 'Công ty TNHH Kiểm toán và Định giá Quốc tế', 'qualified', 1, 'Tại ngày 31/12/2025, lỗ lũy kế của Công ty là 73.526.377.517 đồng, chiếm 91,6% vốn chủ sở hữu. Năm 2024, Công ty không phát sinh doanh thu, năm 2025 Công ty có phát sinh doanh thu, nhưng lợi nhuận chủ yếu đến từ việc hoàn nhập các khoản dự phòng. Điều này cho thấy khả năng hoạt động liên tục của Công ty có thể bị ảnh hưởng.'),
('VNI_2024_consolidated', 'VNI', 2024, 'consolidated', 'AASCS', 'qualified', 1, 'Nợ ngắn hạn vượt tài sản ngắn hạn 64.217.456.385 VND, lưu chuyển tiền tệ từ hoạt động kinh doanh âm, và nghi ngờ về khả năng hoạt động liên tục.'),
('VNH_2024_consolidated', 'VNH', 2024, 'consolidated', 'Công ty TNHH Kiểm toán và Tư vấn UHY - Chi nhánh Hà Nội', 'disclaimer', 1, 'Tại ngày 31/12/2024, lỗ lũy kế của Công ty là 75.710.943.108 đồng. Trong năm 2024, Công ty tạm dừng các hoạt động kinh doanh, không phát sinh doanh thu bán hàng và cung cấp dịch vụ, chỉ phát sinh chi phí thuế môn bài và phí chuyển tiền.'),
('VNH_2023_consolidated', 'VNH', 2023, 'consolidated', 'Chi nhánh Hà Nội - Công ty TNHH Kiểm toán và Tư vấn UHY', 'unqualified', 0, NULL),
('VNH_2021_consolidated', 'VNH', 2021, 'consolidated', 'Chi nhánh Công ty TNHH Kiểm toán - Tư vấn Đất Việt tại Hà Nội', 'qualified', 1, 'Lỗ lũy kế của công ty là 76.526.195.494 đồng và nợ ngắn hạn vượt quá tài sản ngắn hạn với số tiền là 4.834.783.141 đồng. Công ty đã bị Cục thuế Thành phố Hồ Chí Minh ra thông báo về việc cưỡng chế hóa đơn không còn giá trị sử dụng do không chấp hành nộp tiền nợ thuế và tiền chậm nộp. Công ty đang hoạt động thương mại cầm chừng.'),
('VNH_2022_consolidated', 'VNH', 2022, 'consolidated', 'Công ty TNHH Kiểm toán và Tư vấn UHY', 'qualified', 1, 'Tại ngày 31/12/2022, lỗ lũy kế của công ty là 76.595.333.039 đồng; một số khoản nợ phải trả quá hạn thanh toán; Công ty đã bị Cục thuế Thành phố Hồ Chí Minh ra thông báo về việc cương chế hóa đơn không còn giá trị sử dụng do không chấp hành nộp tiền nợ thuế và tiền chậm nộp. Các vấn đề này tồn tại các yếu tố không chắc chắn ảnh hưởng đến khả năng hoạt động liên tục của Công ty.'),
('VNH_2020_consolidated', 'VNH', 2020, 'consolidated', 'Công ty TNHH Kiểm toán – Tư vấn Đất Việt', 'unqualified', 0, NULL),
('VNH_2019_consolidated', 'VNH', 2019, 'consolidated', 'Công ty TNHH Kiểm toán - Tư vấn Đất Việt', 'unqualified', 0, NULL),
('VNH_2018_consolidated', 'VNH', 2018, 'consolidated', 'Công ty TNHH Kiểm toán và Thẩm định giá Việt Nam (AVA)', 'unqualified', 1, 'Trong năm 2018 Công ty tiếp tục lỗ 1.262.052.983 VND. Đến ngày 31 tháng 12 năm 2018 khoản lỗ lũy kế được ghi nhận là 87.334.899.150 VND. Ngoài ra tại ngày 31 tháng 12 năm 2018 nợ phải trả ngắn hạn lớn hơn tổng tài sản ngắn hạn 8.332.466.341 VND.'),
('VNH_2015_consolidated', 'VNH', 2015, 'consolidated', 'Công ty TNHH Kiểm toán DTL (RSM Vietnam)', 'unqualified', 0, NULL),
('VNH_2017_consolidated', 'VNH', 2017, 'consolidated', 'Công ty TNHH PKF Việt Nam', 'unqualified', 1, 'Năm tài chính kết thúc ngày 31 tháng 12 năm 2017 Công ty tiếp tục lỗ, đến ngày 31 tháng 12 năm 2017 khoản lỗ lũy kế được ghi nhận là 86.072.846.167 đồng. Ngoài ra tại ngày 31 tháng 12 năm 2017 nợ phải trả ngắn hạn lớn hơn tổng tài sản ngắn hạn 4.233.281.319 đồng. Các yếu tố này có thể ảnh hưởng đến khả năng hoạt động liên tục của Công ty.'),
('VNH_2016_consolidated', 'VNH', 2016, 'consolidated', 'Công ty TNHH Kiểm toán DFK Việt Nam', 'unqualified', 1, 'Trong năm 2016, Công ty đã tiến hành bán thanh lý hầu như toàn bộ tài sản của Công ty gồm hàng tồn kho và tài sản cố định nhằm thanh toán hết các khoản nợ gốc và lãi vay tại các ngân hàng. Việc này làm gia tăng nghi ngờ về khả năng hoạt động liên tục của Công ty.'),
('VNG_2025_consolidated', 'VNG', 2025, 'consolidated', 'Công ty TNHH Kiểm toán và Tư vấn UHY', 'unqualified', 1, 'Nhóm Công ty chưa ghi nhận khoản nghĩa vụ tiền thuê đất có mặt nước chuyên dùng phát sinh bổ sung với tổng số tiền là 100,71 tỷ đồng, do đang chờ kết luận chính thức của cơ quan Nhà nước có thẩm quyền.'),
('VNG_2025_parent', 'VNG', 2025, 'parent', 'UHY Auditing and Consulting Co., Ltd.', 'unqualified', 0, NULL),
('VNG_2024_consolidated', 'VNG', 2024, 'consolidated', 'Ernst & Young Vietnam Limited', 'unqualified', 0, NULL),
('VNG_2024_parent', 'VNG', 2024, 'parent', 'Ernst & Young Vietnam Limited', 'unqualified', 0, NULL);
