('VNG_2021_consolidated', 'VNG', 2021, 'consolidated', 'Ernst & Young Việt Nam', 'unqualified', 0, NULL),
('VNG_2021_parent', 'VNG', 2021, 'parent', 'Ernst & Young Việt Nam', 'unqualified', 0, NULL),
('VNG_2020_parent', 'VNG', 2020, 'parent', 'Ernst & Young Việt Nam', 'unqualified', 0, NULL),
('VNG_2019_consolidated', 'VNG', 2019, 'consolidated', 'Công ty Trách nhiệm Hữu hạn Ernst & Young Việt Nam', 'unqualified', 0, NULL),
('VNG_2020_consolidated', 'VNG', 2020, 'consolidated', 'Ernst & Young Việt Nam', 'unqualified', 0, NULL),
('VNG_2017_parent', 'VNG', 2017, 'parent', 'AASC', 'unqualified', 1, 'Tại ngày 31 tháng 12 năm 2017, tài sản ngắn hạn nhỏ hơn nợ ngắn hạn khoảng 28 tỷ đồng, cho thấy sự tồn tại của yếu tố không chắc chắn trọng yếu có thể dẫn đến nghi ngờ về khả năng hoạt động liên tục của Công ty.'),
('VNG_2017_consolidated', 'VNG', 2017, 'consolidated', 'AASC', 'unqualified', 0, NULL),
('VNG_2019_parent', 'VNG', 2019, 'parent', 'Ernst & Young Việt Nam', 'unqualified', 0, NULL),
('VNG_2018_parent', 'VNG', 2018, 'parent', 'AASC Auditing Firm', 'unqualified', 1, 'Tài sản ngắn hạn nhỏ hơn Nợ ngắn hạn 59,4 tỷ đồng, dẫn đến nghi ngờ về khả năng hoạt động liên tục.'),
('VNG_2018_consolidated', 'VNG', 2018, 'consolidated', 'Công ty TNHH Hăng Kiểm toán AASC', 'unqualified', 0, NULL),
('VNG_2016_consolidated', 'VNG', 2016, 'consolidated', 'Công ty TNHH Hãng Kiểm toán AASC', 'unqualified', 0, NULL),
('VNG_2016_parent', 'VNG', 2016, 'parent', 'AASC', 'unqualified', 0, NULL),
('VNG_2015_consolidated', 'VNG', 2015, 'consolidated', 'AASC', 'unqualified', 1, 'Để đảm bảo nguồn vốn cho Dự án sửa chữa Khách sạn Golf Cần Thơ, Công ty đã thực hiện vay ngắn hạn các đối tác, dẫn đến chỉ tiêu Nợ phải trả ngắn hạn lớn hơn tài sản ngắn hạn, có dấu hiện không chắc chắn có thể ảnh hưởng đến khả năng hoạt động liên tục của Công ty. Tuy nhiên, Tập đoàn Thành Thành Công đã có cam kết tài trợ vốn cho dự án Khách sạn Golf Cần Thơ, do vậy Công ty vẫn đảm bảo khả năng thanh toán trong thời gian tới.'),
('VNG_2015_parent', 'VNG', 2015, 'parent', 'AASC', 'unqualified', 0, NULL),
('VNF_2025_consolidated', 'VNF', 2025, 'consolidated', 'PwC (Việt Nam)', 'unqualified', 0, NULL),
('VNF_2025_parent', 'VNF', 2025, 'parent', 'PwC Việt Nam', 'unqualified', 0, NULL);
